import json, websocket

# Connect to CDP and get form elements
ws_url = None
import requests
resp = requests.get("http://localhost:9222/json")
tabs = resp.json()
print(f"Found {len(tabs)} tabs")
for t in tabs:
    if "amazon.jobs" in t.get("title",""):
        ws_url = t["webSocketDebuggerUrl"]
        print(f"Tab: {t['title']} - {t['url']}")

if not ws_url:
    # Use the first tab
    ws_url = tabs[0]["webSocketDebuggerUrl"]
    print(f"Using first tab: {tabs[0]['title']}")

print(f"WS URL: {ws_url}")

def send_cmd(ws, method, params=None):
    if params is None:
        params = {}
    msg = json.dumps({"id": 1, "method": method, "params": params})
    ws.send(msg)
    return json.loads(ws.recv())

ws = websocket.create_connection(ws_url)

# Get the form elements
result = send_cmd(ws, "Runtime.evaluate", {
    "expression": """
    (() => {
        const form = document.querySelector('form') || document.querySelector('[role="form"]');
        if (!form) return "No form found";

        const elements = form.querySelectorAll('input, select, textarea, button');
        const fields = [];
        elements.forEach(el => {
            const rect = el.getBoundingClientRect();
            fields.push({
                tag: el.tagName,
                type: el.type || '',
                name: el.name || '',
                id: el.id || '',
                placeholder: el.placeholder || '',
                label: '',
                x: Math.round(rect.x),
                y: Math.round(rect.y),
                width: Math.round(rect.width),
                height: Math.round(rect.height)
            });
        });

        // Also get labels
        form.querySelectorAll('label').forEach(label => {
            const for_attr = label.getAttribute('for');
            if (for_attr) {
                const input = document.getElementById(for_attr);
                if (input) {
                    const field = fields.find(f => f.id === for_attr);
                    if (field) field.label = label.textContent.trim();
                }
            }
        });

        return JSON.stringify(fields, null, 2);
    })()
    """,
    "returnByValue": True
})

print("\n--- Form Fields ---")
print(result.get("result", {}).get("value", "Error"))

ws.close()
