)

def cmd(method, params=None):
    if params is None: params = {}
    ws.send(json.dumps({"id": 1, "method": method, "params": params}))
    return json.loads(ws.recv())

# First, clear all fields
r = cmd("Runtime.evaluate", {
    "expression": """
    (() => {
        document.querySelectorAll('input[type="text"], input[type="tel"]').forEach(el => {
            el.value = '';
        });
        return 'cleared';
    })()
    """,
    "returnByValue": True
})

# Get the input elements and their positions
r = cmd("Runtime.evaluate", {
    "expression": """
    JSON.stringify({
        first_name: (()=>{const e=document.querySelector('input[name*="first_name"]'); return e ? {x: e.getBoundingClientRect().x, y: e.getBoundingClientRect().y, w: e.offsetWidth, h: e.offsetHeight} : null})(),
        last_name: (()=>{const e=document.querySelector('input[name*="last_name"]'); return e ? {x: e.getBoundingClientRect().x, y: e.getBoundingClientRect().y} : null})(),
        email: (()=>{const e=document.querySelector('input[name*="email"]'); return e ? {x: e.getBoundingClientRect().x, y: e.getBoundingClientRect().y} : null})(),
        phone: (()=>{const e=document.querySelector('input[type="tel"]'); return e ? {x: e.getBoundingClientRect().x, y: e.getBoundingClientRect().y} : null})(),
        address: (()=>{const e=document.querySelector('input[placeholder*="line 1"]'); return e ? {x: e.getBoundingClientRect().x, y: e.getBoundingClientRect().y} : null})(),
        city: (()=>{const e=document.querySelector('input[placeholder*="city"]'); return e ? {x: e.getBoundingClientRect().x, y: e.getBoundingClientRect().y} : null})(),
        zip: (()=>{const e=document.querySelector('input[placeholder*="postal"]'); return e ? {x: e.getBoundingClientRect().x, y: e.getBoundingClientRect().y} : null})(),
        country: (()=>{const e=document.querySelector('select'); return e ? {x: e.getBoundingClientRect().x, y: e.getBoundingClientRect().y} : null})()
    })
    """,
    "returnByValue": True
})
positions = json.loads(r['result']['result']['value'])
print(f"Field positions:")
for k, v in positions.items():
    print(f"  {k}: {v}")

# Use Input.dispatchMouseEvent to click on each field, then Input.insertText to type
def click_and_type(selector, text):
    # Get element center
    r = cmd("Runtime.evaluate", {
        "expression": f"""
        (() => {{
            const el = document.querySelector('{selector}');
            if(!el) return JSON.stringify({{error: 'not found'}});
            const rect = el.getBoundingClientRect();
            el.focus();
            return JSON.stringify({{x: rect.x + rect.width/2, y: rect.y + rect.height/2}});
        }})()
        """,
        "returnByValue": True
    })
    pos = json.loads(r['result']['result']['value'])
    if 'error' in pos:
        return f"Error: {pos['error']}"

    # Click on the field
    x, y = int(pos['x']), int(pos['y'])
    cmd("Input.dispatchMouseEvent", {
        "type": "mousePressed",
        "x": x,
        "y": y,
        "button": "left",
        "clickCount": 1
    })
    cmd("Input.dispatchMouseEvent", {
        "type": "mouseReleased",
        "x": x,
        "y": y,
        "button": "left",
        "clickCount": 1
    })
    time.sleep(0.2)

    # Clear existing and type new text
    cmd("Input.dispatchKeyEvent", {
        "type": "keyDown",
        "windowsVirtualKeyCode": 0x2E,  # Delete
        "key": "Delete"
    })
    cmd("Input.dispatchKeyEvent", {
        "type": "keyUp",
        "windowsVirtualKeyCode": 0x2E,
        "key": "Delete"
    })

    # Select all and delete
    cmd("Input.dispatchKeyEvent", {
        "type": "rawKeyDown",
        "windowsVirtualKeyCode": 0x41,  # A
        "key": "a",
        "modifiers": 8  # Ctrl/Meta
    })
